external_knowledge:
- "Commercial giants" refers to commercial buildings;
- "Energy footprint" is a metaphorical term used to describe the site energy use intensity (site_eui);
- "Crowned with the Energy Star badge" refers to obtaining the Energy Star certification.

sql:
SELECT COUNT(*) as count
FROM outliers
WHERE outlier_type = 'high energy consumption';

SELECT DISTINCT b.property_name, b.city
FROM buildings b
JOIN outliers o ON b.building_id = o.building_id;

SELECT b.building_id, b.property_name, ed.site_eui
FROM buildings b
INNER JOIN energy_data ed ON b.building_id = ed.building_id;

SELECT data_year, SUM(electricity) AS total_electricity_consumption
FROM energy_data
GROUP BY data_year;

SELECT b.property_name, e.site_eui
FROM buildings b
JOIN energy_data e ON b.building_id = e.building_id
WHERE e.site_eui = (
  SELECT MAX(site_eui) FROM energy_data
) OR e.site_eui = (
  SELECT MIN(site_eui) FROM energy_data
)
ORDER BY e.site_eui DESC;
